const text = $json.text;

return [{
  json: {
    transcript: text
  }
}];

// Simple hash without crypto (works in n8n)

const text = $('Mock Data Input').first().json.transcript ||  $input.first().json.content || '';

let hash = 0;
for (let i = 0; i < text.length; i++) {
  const char = text.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash |= 0;
}

return [{
  ...$json,
  transcript_hash: hash.toString()
}];

const items = $input.all();

const valid = items.filter(i => i.json && i.json.id);

return [
  {
    json: {
      hasDuplicate: valid.length > 0,
      count: valid.length
    }
  }
];

const input = $('Mock Data Input').first().json;
const data = $('Transcript Fingerprint Generator').first().json.output;

return [{
  content: `
Meeting: $('Mock Data Input').first().json.meeting_title
Date: $('Mock Data Input').first().json.meeting_date

Summary:
${data.summary}

Decision:
${data.decision}

Action Items:
${data.action_items.join(", ")}

Contradiction:
${data.contradiction_report}
  `,
  metadata: {
    meeting_title: input.meeting_title,
    date: input.meeting_date,
    decision: data.decision,
    transcript_hash: $('Transcript Fingerprint Generator').first().json.transcript_hash,
    hashDataWithTranscript: $('Audio Transcription (OpenAI Whisper)')
  }
}];

